using Microsoft.ML;
using Microsoft.Extensions.ML;
using ChurnPredictor.Models;

var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

// Load and prepare data
var dataView = mlContext.Data.LoadFromTextFile<ChurnInput>(
    dataPath, hasHeader: true, separatorChar: ',');

var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);

// Build the training pipeline
var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

// Train the model
var model = pipeline.Fit(split.TrainSet);

// Evaluate on the test set
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions);
Console.WriteLine($"AUC: {metrics.AreaUnderRocCurve:F4}  Accuracy: {metrics.Accuracy:F4}  F1: {metrics.F1Score:F4}");

// Save the trained model
var modelPath = Path.Combine(AppContext.BaseDirectory, "churn-model.zip");
mlContext.Model.Save(model, dataView.Schema, modelPath);

// Set up the web app with pooled prediction engine
var builder = WebApplication.CreateBuilder(args);

builder.Services.AddPredictionEnginePool<ChurnInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (PredictionEnginePool<ChurnInput, ChurnPrediction> pool, ChurnRequest req) =>
{
    var input = new ChurnInput
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };

    var prediction = pool.Predict(input);

    return Results.Ok(new
    {
        Churned = prediction.Churned,
        Probability = prediction.Probability
    });
});

app.Run();

record ChurnRequest(float Age, float Income, string Region, float PurchaseHistory);

